begin
wwv_flow_imp_shared.create_plugin(
 p_id=>wwv_flow_imp.id(77062407709248682)
,p_plugin_type=>'DYNAMIC ACTION'
,p_name=>'IG_QUICK_SWITCH'
,p_display_name=>'IG Quick Switch'
,p_category=>'COMPONENT'
,p_javascript_file_urls=>'#PLUGIN_FILES#switch.js'
,p_css_file_urls=>'#PLUGIN_FILES#switch.css'
,p_plsql_code=>wwv_flow_string.join(wwv_flow_t_varchar2(
'FUNCTION render_ig_switch (',
'    p_dynamic_action IN apex_plugin.t_dynamic_action,',
'    p_plugin         IN apex_plugin.t_plugin ',
') RETURN apex_plugin.t_dynamic_action_render_result IS',
'    l_result apex_plugin.t_dynamic_action_render_result;',
'BEGIN',
'    l_result.javascript_function := ''function(){ inicializarIgSwitch("'' || p_dynamic_action.attribute_01 || ''"); }'';',
'    RETURN l_result;',
'END render_ig_switch;'))
,p_api_version=>1
,p_render_function=>'render_ig_switch'
,p_substitute_attributes=>true
,p_version_scn=>39025866778734
,p_subscribe_plugin_settings=>true
,p_help_text=>wwv_flow_string.join(wwv_flow_t_varchar2(
'IG Quick Switch [Plug-In]',
'',
'This Dynamic Action plug-in converts native Interactive Grid text columns containing ''S''/''Y'' or ''N'' values into interactive Switch toggles. It allows users to toggle boolean values directly in Read-Only mode without double-clicking to enter the edit '
||'state.',
'',
'How to use:',
'1. Ensure your target Interactive Grid column is set to Text Field or Display Only.',
'2. Turn OFF the "Value Protected" attribute for the target column.',
'3. Add this Action on Page Load and specify the column name(s) in the Action Settings.',
'',
'Author: cleiton.rcruz@gmail.com'))
,p_version_identifier=>'2.0'
,p_about_url=>'https://github.com/cleitonrcruz/oracle-apex-ig-quick-switch'
,p_files_version=>25
);
wwv_flow_imp_shared.create_plugin_attribute(
 p_id=>wwv_flow_imp.id(26912455816210740)
,p_plugin_id=>wwv_flow_imp.id(77062407709248682)
,p_attribute_scope=>'COMPONENT'
,p_attribute_sequence=>1
,p_display_sequence=>10
,p_prompt=>'Colunas Alvo'
,p_attribute_type=>'TEXT'
,p_is_required=>false
,p_is_translatable=>false
,p_examples=>wwv_flow_string.join(wwv_flow_t_varchar2(
'For a single column: IS_ACTIVE',
'To convert multiple columns in the same grid into Switches: IS_ACTIVE, IS_BLOCKED, IS_CONFIRMED'))
,p_help_text=>'Enter the column name (or a comma-separated list of column names) from the Interactive Grid that you want to automatically convert into a visual Switch toggle (Y/N). The source column must be visible in the grid (Text Field or Display Only) with the '
||'"Value Protected" attribute turned OFF so the Plugin can manipulate it.'
);
end;
